svg.script:
        const getEl = id => document.getElementById(id);

        function updateLightMode(isDark) {
            const color = isDark ? 'hsl(120, 100%, 80%)' : 'white';
            const opacite = isDark ? '0.4' : '1';
            const slope = isDark ? '0.4' : '0.9';

            // Correction de la couleur
            const b = getEl('blanc');
            b.style.stroke = b.style.fill = color;
            getEl('m1').style.fill = getEl('h1').style.fill = getEl('r1').style.fill = color;
            
            // Correction de l'opacité du décor
            getEl('ah').style.opacity = opacite;

            // Mise à jour du filtre de luminosité
            document.querySelectorAll('.bri').forEach(el => el.setAttribute("slope", slope));
        }

        function rotateClock() {
            const now = new Date();
            const m = (now.getMinutes() + now.getSeconds()/60) * 6;
            const h = (now.getHours() % 12) * 30 + (m / 12);
            getEl('h').setAttribute("transform", `rotate(${h} 100 100)`);
            getEl('m').setAttribute("transform", `rotate(${m} 100 100)`);
            requestAnimationFrame(rotateClock);
        }

        function handleOrientation(event) {
            const beta = event.beta == null ? -200 : Math.round(event.beta) * 2 - 300;
            const gamma = Math.round(event.gamma * 0.6) * -1 / 0.6;
            getEl('ah').setAttribute("transform", `rotate(${gamma} 100 200) translate(0 ${beta})`);
        }

        async function initSensors() {
            if (typeof DeviceOrientationEvent !== 'undefined' && typeof DeviceOrientationEvent.requestPermission === 'function') {
                try {
                    const permission = await DeviceOrientationEvent.requestPermission();
                    if (permission === 'granted') window.addEventListener("deviceorientation", handleOrientation);
                } catch (e) { console.error(e); }
            } else {
                window.addEventListener("deviceorientation", handleOrientation);
            }
            getEl('overlay').style.display = 'none'; 
        }

        window.addEventListener('load', () => {
            rotateClock();
            const query = window.matchMedia('(prefers-color-scheme: dark)');
            updateLightMode(query.matches);
            query.addEventListener('change', e => updateLightMode(e.matches));
        });
